"""CulturalExchangeHub
=======================

A web-based platform back-end that connects individuals across the world through
interactive cultural-exchange experiences: virtual tours of cultural landmarks,
real-time language practice, and live/recorded cultural workshops, plus the tools
to share cultural backgrounds and to rate every experience.

The system is delivered as a single, dependency-free Python module (standard
library only) so that it can run anywhere.  It is organised into logical
sub-modules that mirror how the project would be split across files.  Each
sub-module is introduced with a ``# <file_name>.py`` banner.  Because everything
lives in one physical file, the sub-modules share a single namespace and no
cross-imports are required.

Module build order (enforced by :class:`CulturalExchangeHub`):

    1. user_management   -- must exist before anything else
    2. virtual_tour      -- built after user_management
    3. language_learning -- built after virtual_tour
    4. cultural_workshop -- built after language_learning
    5. feedback          -- built last, after every other module

Development process followed for this deliverable: created, revised, then
optimised for clarity, validation and correctness.
"""

from __future__ import annotations

import hashlib
import re
import secrets
import sys
import uuid
from dataclasses import dataclass, field
from datetime import datetime, timedelta, timezone
from enum import Enum
from typing import Callable, Dict, Generic, List, Optional, Tuple, TypeVar


# ======================================================================
# exceptions.py -- Domain-specific exception hierarchy
# ======================================================================
class CulturalExchangeError(Exception):
    """Base class for every error raised by the platform."""


class ValidationError(CulturalExchangeError):
    """Raised when user supplied data fails a validation rule."""


class NotFoundError(CulturalExchangeError):
    """Raised when a referenced entity does not exist."""


class DuplicateError(CulturalExchangeError):
    """Raised when a unique constraint would be violated."""


class AuthenticationError(CulturalExchangeError):
    """Raised when credentials cannot be verified."""


class AuthorizationError(CulturalExchangeError):
    """Raised when a user is not permitted to perform an action."""


class CapacityError(CulturalExchangeError):
    """Raised when a session/workshop has no free seats."""


class ProfileIncompleteError(CulturalExchangeError):
    """Raised when an action requires a completed profile."""


class ModuleDependencyError(CulturalExchangeError):
    """Raised when a module is activated before its dependencies."""


# ======================================================================
# utils.py -- Shared helpers: ids, time, hashing, validation, translation
# ======================================================================
_EMAIL_RE = re.compile(r"^[A-Za-z0-9._%+\-]+@[A-Za-z0-9.\-]+\.[A-Za-z]{2,}$")
_USERNAME_RE = re.compile(r"^[A-Za-z0-9_.\-]{3,30}$")
_ALLOWED_IMAGE_EXT = {"png", "jpg", "jpeg", "gif", "webp"}
_MAX_PICTURE_BYTES = 5 * 1024 * 1024  # 5 MB


def generate_id(prefix: str) -> str:
    """Return a short, collision-resistant identifier with a readable prefix."""
    return f"{prefix}_{uuid.uuid4().hex[:12]}"


def utcnow() -> datetime:
    """Return a timezone-aware UTC timestamp."""
    return datetime.now(timezone.utc)


def hash_password(password: str, *, salt: Optional[str] = None) -> str:
    """Hash a password using PBKDF2-HMAC-SHA256 with a per-user random salt.

    The returned string embeds the algorithm parameters so it is self
    describing: ``pbkdf2_sha256$<iterations>$<salt>$<hexdigest>``.
    """
    iterations = 120_000
    salt = salt or secrets.token_hex(16)
    digest = hashlib.pbkdf2_hmac(
        "sha256", password.encode("utf-8"), salt.encode("utf-8"), iterations
    ).hex()
    return f"pbkdf2_sha256${iterations}${salt}${digest}"


def verify_password(password: str, encoded: str) -> bool:
    """Constant-time verification of a password against an encoded hash."""
    try:
        algorithm, iter_s, salt, _ = encoded.split("$")
    except ValueError:
        return False
    if algorithm != "pbkdf2_sha256":
        return False
    candidate = hashlib.pbkdf2_hmac(
        "sha256", password.encode("utf-8"), salt.encode("utf-8"), int(iter_s)
    ).hex()
    expected = encoded.split("$")[-1]
    return secrets.compare_digest(candidate, expected)


def validate_email(email: str) -> str:
    email = (email or "").strip()
    if not _EMAIL_RE.match(email):
        raise ValidationError(f"Invalid email address: {email!r}")
    return email.lower()


def validate_username(username: str) -> str:
    username = (username or "").strip()
    if not _USERNAME_RE.match(username):
        raise ValidationError(
            "Username must be 3-30 chars (letters, digits, '_', '.', '-')."
        )
    return username


def validate_password_strength(password: str) -> None:
    if password is None or len(password) < 8:
        raise ValidationError("Password must be at least 8 characters long.")
    if not any(c.isalpha() for c in password) or not any(c.isdigit() for c in password):
        raise ValidationError("Password must contain both letters and digits.")


def validate_rating(rating: int) -> int:
    if not isinstance(rating, int) or isinstance(rating, bool):
        raise ValidationError("Rating must be an integer.")
    if not 1 <= rating <= 5:
        raise ValidationError("Rating must be between 1 and 5.")
    return rating


# ----------------------------------------------------------------------
# Translation tool used by the language-learning module.
# ----------------------------------------------------------------------
_LANG_ALIASES = {
    "en": "en", "eng": "en", "english": "en",
    "es": "es", "spa": "es", "spanish": "es", "espanol": "es", "español": "es",
    "fr": "fr", "fra": "fr", "french": "fr", "francais": "fr", "français": "fr",
    "ja": "ja", "jp": "ja", "jpn": "ja", "japanese": "ja", "日本語": "ja",
    "de": "de", "ger": "de", "german": "de", "deutsch": "de",
    "it": "it", "ita": "it", "italian": "it", "italiano": "it",
}


def normalize_language(language: str) -> str:
    """Map a free-form language name/code to a canonical ISO-639-1 code."""
    key = (language or "").strip().lower()
    return _LANG_ALIASES.get(key, key)


class TranslationTool:
    """A small, deterministic phrase/word translator.

    It is intentionally lightweight (a built-in phrasebook) so the platform has
    a working translation aid without any network dependency.  Unknown text is
    returned with a clear ``[lang]`` annotation rather than silently dropped.
    """

    _PHRASEBOOK: List[Dict[str, str]] = [
        {"en": "hello", "es": "hola", "fr": "bonjour", "ja": "こんにちは", "de": "hallo", "it": "ciao"},
        {"en": "goodbye", "es": "adiós", "fr": "au revoir", "ja": "さようなら", "de": "auf wiedersehen", "it": "arrivederci"},
        {"en": "thank you", "es": "gracias", "fr": "merci", "ja": "ありがとう", "de": "danke", "it": "grazie"},
        {"en": "please", "es": "por favor", "fr": "s'il vous plaît", "ja": "お願いします", "de": "bitte", "it": "per favore"},
        {"en": "good morning", "es": "buenos días", "fr": "bonjour", "ja": "おはよう", "de": "guten morgen", "it": "buongiorno"},
        {"en": "good night", "es": "buenas noches", "fr": "bonne nuit", "ja": "おやすみ", "de": "gute nacht", "it": "buonanotte"},
        {"en": "how are you", "es": "cómo estás", "fr": "comment ça va", "ja": "お元気ですか", "de": "wie geht es dir", "it": "come stai"},
        {"en": "welcome", "es": "bienvenido", "fr": "bienvenue", "ja": "ようこそ", "de": "willkommen", "it": "benvenuto"},
        {"en": "friend", "es": "amigo", "fr": "ami", "ja": "友達", "de": "freund", "it": "amico"},
        {"en": "yes", "es": "sí", "fr": "oui", "ja": "はい", "de": "ja", "it": "sì"},
        {"en": "no", "es": "no", "fr": "non", "ja": "いいえ", "de": "nein", "it": "no"},
    ]

    def __init__(self) -> None:
        # Index every (language, lowercased-text) -> entry for fast lookup.
        self._index: Dict[Tuple[str, str], Dict[str, str]] = {}
        for entry in self._PHRASEBOOK:
            for lang, text in entry.items():
                self._index.setdefault((lang, text.lower()), entry)

    @property
    def supported_languages(self) -> List[str]:
        return ["en", "es", "fr", "ja", "de", "it"]

    @staticmethod
    def _apply_case(source: str, translated: str) -> str:
        if source[:1].isupper():
            return translated[:1].upper() + translated[1:]
        return translated

    def translate(self, text: str, source: str, target: str) -> str:
        """Translate ``text`` from ``source`` language to ``target`` language."""
        if not text:
            return text
        src = normalize_language(source)
        tgt = normalize_language(target)
        if src == tgt:
            return text

        # 1) Whole-phrase match.
        entry = self._index.get((src, text.strip().lower()))
        if entry and tgt in entry:
            return self._apply_case(text.strip(), entry[tgt])

        # 2) Word-by-word best effort.
        translated_words: List[str] = []
        matched_any = False
        for word in text.split():
            core = word.strip(".,!?;:\"'()").lower()
            word_entry = self._index.get((src, core))
            if word_entry and tgt in word_entry:
                translated_words.append(self._apply_case(word, word_entry[tgt]))
                matched_any = True
            else:
                translated_words.append(word)
        if matched_any:
            return " ".join(translated_words)

        # 3) Unknown text -> explicit annotation (never silently lost).
        return f"[{tgt}] {text}"


# ======================================================================
# repository.py -- Generic in-memory repository
# ======================================================================
T = TypeVar("T")


class InMemoryRepository(Generic[T]):
    """A tiny generic store keyed by an ``id`` attribute on each item."""

    def __init__(self, entity_name: str) -> None:
        self._entity_name = entity_name
        self._items: Dict[str, T] = {}

    def add(self, item: T) -> T:
        self._items[item.id] = item  # type: ignore[attr-defined]
        return item

    def get(self, item_id: str) -> Optional[T]:
        return self._items.get(item_id)

    def require(self, item_id: str) -> T:
        item = self._items.get(item_id)
        if item is None:
            raise NotFoundError(f"{self._entity_name} {item_id!r} not found.")
        return item

    def exists(self, item_id: str) -> bool:
        return item_id in self._items

    def list(self) -> List[T]:
        return list(self._items.values())

    def filter(self, predicate: Callable[[T], bool]) -> List[T]:
        return [item for item in self._items.values() if predicate(item)]

    def delete(self, item_id: str) -> None:
        self._items.pop(item_id, None)

    def __len__(self) -> int:
        return len(self._items)


# ======================================================================
# enums.py -- Shared enumerations
# ======================================================================
class ProficiencyLevel(Enum):
    BEGINNER = "beginner"
    INTERMEDIATE = "intermediate"
    ADVANCED = "advanced"
    NATIVE = "native"

    @property
    def can_teach_level(self) -> bool:
        return self in (ProficiencyLevel.ADVANCED, ProficiencyLevel.NATIVE)


class WorkshopFormat(Enum):
    LIVE = "live"
    RECORDED = "recorded"


class SessionStatus(Enum):
    SCHEDULED = "scheduled"
    ACTIVE = "active"
    ENDED = "ended"
    CANCELLED = "cancelled"


class ExperienceType(Enum):
    VIRTUAL_TOUR = "virtual_tour"
    LANGUAGE_EXCHANGE = "language_exchange"
    WORKSHOP = "workshop"


class ModuleName(Enum):
    USER_MANAGEMENT = "user_management"
    VIRTUAL_TOUR = "virtual_tour"
    LANGUAGE_LEARNING = "language_learning"
    CULTURAL_WORKSHOP = "cultural_workshop"
    FEEDBACK = "feedback"


# ======================================================================
# models.py -- Data models
# ======================================================================
@dataclass
class ProfilePicture:
    filename: str
    content_type: str
    size_bytes: int
    checksum: str
    uploaded_at: datetime = field(default_factory=utcnow)


@dataclass
class Profile:
    """A user's cultural profile."""

    full_name: str = ""
    country: str = ""
    bio: str = ""
    cultural_background: str = ""
    interests: List[str] = field(default_factory=list)
    native_languages: List[str] = field(default_factory=list)
    picture: Optional[ProfilePicture] = None

    @property
    def is_complete(self) -> bool:
        """A profile is complete once the cultural essentials are filled in."""
        return bool(
            self.full_name
            and self.country
            and self.cultural_background
            and self.interests
        )


@dataclass
class User:
    username: str
    email: str
    password_hash: str
    id: str = field(default_factory=lambda: generate_id("usr"))
    created_at: datetime = field(default_factory=utcnow)
    profile: Profile = field(default_factory=Profile)


@dataclass
class Hotspot:
