# ======================================================================
# user_management.py -- Foundation module (must exist before all others)
# ======================================================================
class UserManagementService:
    """Account creation, authentication and cultural-profile management."""

    def __init__(self) -> None:
        self._users: InMemoryRepository[User] = InMemoryRepository("User")
        self._by_username: Dict[str, str] = {}
        self._by_email: Dict[str, str] = {}

    # -- registration / auth -------------------------------------------------
    def register(self, username: str, email: str, password: str) -> User:
        username = validate_username(username)
        email = validate_email(email)
        validate_password_strength(password)
        if username.lower() in self._by_username:
            raise DuplicateError(f"Username {username!r} is already taken.")
        if email in self._by_email:
            raise DuplicateError(f"Email {email!r} is already registered.")

        user = User(username=username, email=email, password_hash=hash_password(password))
        self._users.add(user)
        self._by_username[username.lower()] = user.id
        self._by_email[email] = user.id
        return user

    def authenticate(self, identifier: str, password: str) -> User:
        identifier = (identifier or "").strip()
        user_id = self._by_username.get(identifier.lower()) or self._by_email.get(
            identifier.lower()
        )
        if user_id is None:
            raise AuthenticationError("Unknown username or email.")
        user = self._users.require(user_id)
        if not verify_password(password, user.password_hash):
            raise AuthenticationError("Incorrect password.")
        return user

    # -- lookups -------------------------------------------------------------
    def get_user(self, user_id: str) -> User:
        return self._users.require(user_id)

    def exists(self, user_id: str) -> bool:
        return self._users.exists(user_id)

    def list_users(self) -> List[User]:
        return self._users.list()

    # -- profile management --------------------------------------------------
    def update_profile(
        self,
        user_id: str,
        *,
        full_name: Optional[str] = None,
        country: Optional[str] = None,
        bio: Optional[str] = None,
        cultural_background: Optional[str] = None,
        interests: Optional[List[str]] = None,
        native_languages: Optional[List[str]] = None,
    ) -> Profile:
        profile = self._users.require(user_id).profile
        if full_name is not None:
            profile.full_name = full_name.strip()
        if country is not None:
            profile.country = country.strip()
        if bio is not None:
            profile.bio = bio.strip()
        if cultural_background is not None:
            profile.cultural_background = cultural_background.strip()
        if interests is not None:
            profile.interests = [i.strip() for i in interests if i.strip()]
        if native_languages is not None:
            profile.native_languages = [normalize_language(l) for l in native_languages]
        return profile

    def add_interests(self, user_id: str, interests: List[str]) -> Profile:
        profile = self._users.require(user_id).profile
        for interest in interests:
            cleaned = interest.strip()
            if cleaned and cleaned not in profile.interests:
                profile.interests.append(cleaned)
        return profile

    def upload_profile_picture(
        self, user_id: str, filename: str, content: bytes
    ) -> ProfilePicture:
        user = self._users.require(user_id)
        if "." not in filename:
            raise ValidationError("Picture filename must include an extension.")
        ext = filename.rsplit(".", 1)[-1].lower()
        if ext not in _ALLOWED_IMAGE_EXT:
            raise ValidationError(
                f"Unsupported image type {ext!r}. Allowed: {sorted(_ALLOWED_IMAGE_EXT)}."
            )
        if not content:
            raise ValidationError("Picture content is empty.")
        if len(content) > _MAX_PICTURE_BYTES:
            raise ValidationError("Picture exceeds the 5 MB size limit.")
        picture = ProfilePicture(
            filename=filename,
            content_type=f"image/{'jpeg' if ext == 'jpg' else ext}",
            size_bytes=len(content),
            checksum=hashlib.sha256(content).hexdigest(),
        )
        user.profile.picture = picture
        return picture

    def require_complete_profile(self, user_id: str) -> User:
        user = self._users.require(user_id)
        if not user.profile.is_complete:
            raise ProfileIncompleteError(
                f"User {user.username!r} must complete their profile "
                "(full name, country, cultural background and interests) first."
            )
        return user


# ======================================================================
# virtual_tour.py -- Built after user_management
# ======================================================================
class VirtualTourService:
    """Explore 3D models of cultural landmarks with hotspots and audio guides."""

    def __init__(self, users: UserManagementService) -> None:
        self._users = users
        self._tours: InMemoryRepository[VirtualTour] = InMemoryRepository("VirtualTour")
        self._visits: InMemoryRepository[TourVisit] = InMemoryRepository("TourVisit")

    def create_tour(
        self,
        creator_id: str,
        name: str,
        landmark: str,
        description: str,
        model_3d_url: str,
        location: str = "",
    ) -> VirtualTour:
        self._users.require_complete_profile(creator_id)
        if not name.strip() or not landmark.strip():
            raise ValidationError("Tour name and landmark are required.")
        if not model_3d_url.strip():
            raise ValidationError("A 3D model URL is required for a virtual tour.")
        tour = VirtualTour(
            name=name.strip(),
            landmark=landmark.strip(),
            description=description.strip(),
            created_by=creator_id,
            model_3d_url=model_3d_url.strip(),
            location=location.strip(),
        )
        return self._tours.add(tour)

    def add_hotspot(
        self,
        tour_id: str,
        title: str,
        info: str,
        position: Tuple[float, float, float] = (0.0, 0.0, 0.0),
        audio_url: Optional[str] = None,
    ) -> Hotspot:
        tour = self._tours.require(tour_id)
        if not title.strip():
            raise ValidationError("Hotspot title is required.")
        hotspot = Hotspot(
            title=title.strip(), info=info.strip(), position=position, audio_url=audio_url
        )
        tour.hotspots.append(hotspot)
        return hotspot

    def set_audio_guide(self, tour_id: str, language: str, audio_url: str) -> VirtualTour:
        tour = self._tours.require(tour_id)
        if not audio_url.strip():
            raise ValidationError("Audio guide URL is required.")
        tour.audio_guides[normalize_language(language)] = audio_url.strip()
        return tour

    def start_tour(self, user_id: str, tour_id: str) -> TourVisit:
        self._users.get_user(user_id)
        self._tours.require(tour_id)
        visit = TourVisit(tour_id=tour_id, user_id=user_id)
        return self._visits.add(visit)

    def visit_hotspot(self, visit_id: str, hotspot_id: str) -> Hotspot:
        visit = self._visits.require(visit_id)
        if visit.status is not SessionStatus.ACTIVE:
            raise ValidationError("Cannot interact with a tour that has ended.")
        tour = self._tours.require(visit.tour_id)
        hotspot = next((h for h in tour.hotspots if h.id == hotspot_id), None)
        if hotspot is None:
            raise NotFoundError(f"Hotspot {hotspot_id!r} not found in tour.")
        if hotspot_id not in visit.visited_hotspots:
            visit.visited_hotspots.append(hotspot_id)
        return hotspot

    def end_tour(self, visit_id: str) -> TourVisit:
        visit = self._visits.require(visit_id)
        visit.status = SessionStatus.ENDED
        visit.ended_at = utcnow()
        return visit

    def get_tour(self, tour_id: str) -> VirtualTour:
        return self._tours.require(tour_id)

    def list_tours(self) -> List[VirtualTour]:
        return self._tours.list()

    def exists(self, tour_id: str) -> bool:
        return self._tours.exists(tour_id)


# ======================================================================
# language_learning.py -- Built after virtual_tour
# ======================================================================
class LanguageLearningService:
    """Pair users for real-time language exchange with a translation aid."""

    def __init__(self, users: UserManagementService, translator: TranslationTool) -> None:
        self._users = users
        self._translator = translator
        self._skills: Dict[str, List[LanguageSkill]] = {}
        self._sessions: InMemoryRepository[LanguageExchangeSession] = InMemoryRepository(
            "LanguageExchangeSession"
        )

    def set_language_skills(self, user_id: str, skills: List[LanguageSkill]) -> None:
        self._users.get_user(user_id)
        if not skills:
            raise ValidationError("At least one language skill is required.")
        self._skills[user_id] = list(skills)

    def get_skills(self, user_id: str) -> List[LanguageSkill]:
        return self._skills.get(user_id, [])

    def _can_teach(self, user_id: str, language: str) -> bool:
        code = normalize_language(language)
        return any(
            s.code == code and s.can_teach and s.proficiency.can_teach_level
            for s in self._skills.get(user_id, [])
        )

    def _wants_to_learn(self, user_id: str, language: str) -> bool:
        code = normalize_language(language)
        return any(
            s.code == code and s.wants_to_learn for s in self._skills.get(user_id, [])
        )

    def find_partner(self, user_id: str, learn_language: str) -> User:
        """Find the best partner who can teach ``learn_language``.

        A *mutual* match (the candidate also wants to learn something the
        requester can teach) is preferred over a one-directional match.
        """
        self._users.require_complete_profile(user_id)
        requester_teaches = {
            s.code for s in self._skills.get(user_id, []) if s.can_teach
        }
        mutual: Optional[User] = None
        one_way: Optional[User] = None
        for candidate in self._users.list_users():
            if candidate.id == user_id:
                continue
            if not candidate.profile.is_complete:
                continue
            if not self._can_teach(candidate.id, learn_language):
                continue
            wants = {s.code for s in self._skills.get(candidate.id, []) if s.wants_to_learn}
            if requester_teaches & wants:
                mutual = mutual or candidate
            one_way = one_way or candidate
        partner = mutual or one_way
        if partner is None:
            raise NotFoundError(
                f"No partner available to teach {learn_language!r} right now."
            )
        return partner

    def create_exchange(
        self, user_a: str, user_b: str, language_a: str, language_b: str
    ) -> LanguageExchangeSession:
        self._users.require_complete_profile(user_a)
        self._users.require_complete_profile(user_b)
        if user_a == user_b:
            raise ValidationError("A language exchange needs two distinct users.")
        session = LanguageExchangeSession(
            participant_a=user_a,
            participant_b=user_b,
            language_a=normalize_language(language_a),
            language_b=normalize_language(language_b),
        )
        return self._sessions.add(session)

    def translate(self, text: str, source: str, target: str) -> str:
        return self._translator.translate(text, source, target)

    def send_message(
        self,
        session_id: str,
        sender_id: str,
        text: str,
        source_language: str,
        target_language: str,
    ) -> TranslatedMessage:
        session = self._sessions.require(session_id)
        if session.status is not SessionStatus.ACTIVE:
            raise ValidationError("Cannot send messages in a closed session.")
        if not session.involves(sender_id):
            raise AuthorizationError("Sender is not a participant of this session.")
        if not text.strip():
            raise ValidationError("Message text cannot be empty.")
        message = TranslatedMessage(
            session_id=session_id,
            sender_id=sender_id,
            original_text=text,
            source_language=normalize_language(source_language),
            target_language=normalize_language(target_language),
            translated_text=self._translator.translate(text, source_language, target_language),
        )
        session.messages.append(message)
        return message

    def end_exchange(self, session_id: str) -> LanguageExchangeSession:
        session = self._sessions.require(session_id)
        session.status = SessionStatus.ENDED
        session.ended_at = utcnow()
        return session

    def get_session(self, session_id: str) -> LanguageExchangeSession:
        return self._sessions.require(session_id)

    def list_sessions(self) -> List[LanguageExchangeSession]:
        return self._sessions.list()

    def exists(self, session_id: str) -> bool:
        return self._sessions.exists(session_id)


