class CulturalWorkshopService:
    """Host live and pre-recorded sessions led by cultural experts."""

    def __init__(self, users: UserManagementService) -> None:
        self._users = users
        self._workshops: InMemoryRepository[Workshop] = InMemoryRepository("Workshop")

    def create_workshop(
        self,
        expert_id: str,
        title: str,
        description: str,
        fmt: WorkshopFormat,
        *,
        capacity: int = 50,
        topic: str = "",
        scheduled_at: Optional[datetime] = None,
        recording_url: Optional[str] = None,
    ) -> Workshop:
        self._users.require_complete_profile(expert_id)
        if not title.strip():
            raise ValidationError("Workshop title is required.")
        if capacity <= 0:
            raise ValidationError("Capacity must be a positive number.")
        if fmt is WorkshopFormat.LIVE and scheduled_at is None:
            raise ValidationError("Live workshops require a scheduled time.")
        if fmt is WorkshopFormat.RECORDED and not recording_url:
            raise ValidationError("Recorded workshops require a recording URL.")
        workshop = Workshop(
            title=title.strip(),
            description=description.strip(),
            expert_id=expert_id,
            fmt=fmt,
            capacity=capacity,
            topic=topic.strip(),
            scheduled_at=scheduled_at,
            recording_url=recording_url,
            status=SessionStatus.SCHEDULED if fmt is WorkshopFormat.LIVE else SessionStatus.ACTIVE,
        )
        return self._workshops.add(workshop)

    def _is_participant(self, workshop: Workshop, user_id: str) -> bool:
        return user_id == workshop.expert_id or user_id in workshop.attendees

    def join_workshop(self, user_id: str, workshop_id: str) -> Workshop:
        self._users.get_user(user_id)
        workshop = self._workshops.require(workshop_id)
        if workshop.status in (SessionStatus.ENDED, SessionStatus.CANCELLED):
            raise ValidationError("This workshop is no longer open to join.")
        if user_id == workshop.expert_id:
            raise ValidationError("The hosting expert is already part of the workshop.")
        if user_id in workshop.attendees:
            raise DuplicateError("User has already joined this workshop.")
        if workshop.is_full:
            raise CapacityError("This workshop is full.")
        workshop.attendees.append(user_id)
        return workshop

    def start_workshop(self, workshop_id: str, expert_id: str) -> Workshop:
        workshop = self._workshops.require(workshop_id)
        if workshop.expert_id != expert_id:
            raise AuthorizationError("Only the hosting expert can start the workshop.")
        workshop.status = SessionStatus.ACTIVE
        return workshop

    def end_workshop(self, workshop_id: str, expert_id: str) -> Workshop:
        workshop = self._workshops.require(workshop_id)
        if workshop.expert_id != expert_id:
            raise AuthorizationError("Only the hosting expert can end the workshop.")
        workshop.status = SessionStatus.ENDED
        return workshop

    def ask_question(self, workshop_id: str, user_id: str, text: str) -> WorkshopQuestion:
        workshop = self._workshops.require(workshop_id)
        if user_id not in workshop.attendees:
            raise AuthorizationError("Only attendees can ask questions.")
        if not text.strip():
            raise ValidationError("Question text cannot be empty.")
        question = WorkshopQuestion(workshop_id=workshop_id, user_id=user_id, text=text.strip())
        workshop.questions.append(question)
        return question

    def answer_question(
        self, workshop_id: str, question_id: str, expert_id: str, answer: str
    ) -> WorkshopQuestion:
        workshop = self._workshops.require(workshop_id)
        if workshop.expert_id != expert_id:
            raise AuthorizationError("Only the hosting expert can answer questions.")
        question = next((q for q in workshop.questions if q.id == question_id), None)
        if question is None:
            raise NotFoundError(f"Question {question_id!r} not found.")
        if not answer.strip():
            raise ValidationError("Answer text cannot be empty.")
        question.answer = answer.strip()
        question.answered_by = expert_id
        question.answered_at = utcnow()
        return question

    def post_discussion(self, workshop_id: str, user_id: str, text: str) -> DiscussionPost:
        workshop = self._workshops.require(workshop_id)
        if not self._is_participant(workshop, user_id):
            raise AuthorizationError("Only participants can post in the discussion.")
        if not text.strip():
            raise ValidationError("Discussion text cannot be empty.")
        post = DiscussionPost(workshop_id=workshop_id, user_id=user_id, text=text.strip())
        workshop.discussions.append(post)
        return post

    def reply_to_discussion(
        self, workshop_id: str, post_id: str, user_id: str, text: str
    ) -> DiscussionReply:
        workshop = self._workshops.require(workshop_id)
        if not self._is_participant(workshop, user_id):
            raise AuthorizationError("Only participants can reply in the discussion.")
        post = next((p for p in workshop.discussions if p.id == post_id), None)
        if post is None:
            raise NotFoundError(f"Discussion post {post_id!r} not found.")
        if not text.strip():
            raise ValidationError("Reply text cannot be empty.")
        reply = DiscussionReply(user_id=user_id, text=text.strip())
        post.replies.append(reply)
        return reply

    def get_workshop(self, workshop_id: str) -> Workshop:
        return self._workshops.require(workshop_id)

    def list_workshops(self) -> List[Workshop]:
        return self._workshops.list()

    def exists(self, workshop_id: str) -> bool:
        return self._workshops.exists(workshop_id)


