class FeedbackService:
    """Collect and aggregate ratings/reviews across every experience type."""

    def __init__(self, users: UserManagementService) -> None:
        self._users = users
        self._reviews: InMemoryRepository[Review] = InMemoryRepository("Review")
        self._resolvers: Dict[ExperienceType, Callable[[str], bool]] = {}

    def register_target_resolver(
        self, experience_type: ExperienceType, resolver: Callable[[str], bool]
    ) -> None:
        """Wire in a callback used to confirm a review target exists."""
        self._resolvers[experience_type] = resolver

    def submit_feedback(
        self,
        user_id: str,
        experience_type: ExperienceType,
        target_id: str,
        rating: int,
        comment: str = "",
    ) -> Review:
        self._users.get_user(user_id)
        validate_rating(rating)
        resolver = self._resolvers.get(experience_type)
        if resolver is None or not resolver(target_id):
            raise NotFoundError(
                f"{experience_type.value} target {target_id!r} does not exist."
            )
        duplicate = self._reviews.filter(
            lambda r: r.user_id == user_id
            and r.experience_type is experience_type
            and r.target_id == target_id
        )
        if duplicate:
            raise DuplicateError("User has already reviewed this experience.")
        review = Review(
            user_id=user_id,
            experience_type=experience_type,
            target_id=target_id,
            rating=rating,
            comment=comment.strip(),
        )
        return self._reviews.add(review)

    def get_reviews(self, experience_type: ExperienceType, target_id: str) -> List[Review]:
        return self._reviews.filter(
            lambda r: r.experience_type is experience_type and r.target_id == target_id
        )

    def get_average_rating(
        self, experience_type: ExperienceType, target_id: str
    ) -> Optional[float]:
        reviews = self.get_reviews(experience_type, target_id)
        if not reviews:
            return None
        return round(sum(r.rating for r in reviews) / len(reviews), 2)

    def rating_distribution(
        self, experience_type: ExperienceType, target_id: str
    ) -> Dict[int, int]:
        distribution = {star: 0 for star in range(1, 6)}
        for review in self.get_reviews(experience_type, target_id):
            distribution[review.rating] += 1
        return distribution

    def overall_average(self) -> Optional[float]:
        reviews = self._reviews.list()
        if not reviews:
            return None
        return round(sum(r.rating for r in reviews) / len(reviews), 2)

    def list_reviews(self) -> List[Review]:
        return self._reviews.list()


