# hub.py -- The CulturalExchangeHub facade (enforces module build order)
# ======================================================================
# Each module may only be activated after its dependencies are active.
MODULE_DEPENDENCIES: Dict[ModuleName, List[ModuleName]] = {
    ModuleName.USER_MANAGEMENT: [],
    ModuleName.VIRTUAL_TOUR: [ModuleName.USER_MANAGEMENT],
    ModuleName.LANGUAGE_LEARNING: [ModuleName.VIRTUAL_TOUR],
    ModuleName.CULTURAL_WORKSHOP: [ModuleName.LANGUAGE_LEARNING],
    ModuleName.FEEDBACK: [
        ModuleName.USER_MANAGEMENT,
        ModuleName.VIRTUAL_TOUR,
        ModuleName.LANGUAGE_LEARNING,
        ModuleName.CULTURAL_WORKSHOP,
    ],
}

# The order in which the platform brings modules online.
BUILD_ORDER: List[ModuleName] = [
    ModuleName.USER_MANAGEMENT,
    ModuleName.VIRTUAL_TOUR,
    ModuleName.LANGUAGE_LEARNING,
    ModuleName.CULTURAL_WORKSHOP,
    ModuleName.FEEDBACK,
]


class CulturalExchangeHub:
    """Top-level application service that wires the platform together.

    Modules are activated strictly in dependency order; attempting to activate a
    module before its prerequisites raises :class:`ModuleDependencyError`.  This
    mirrors the project requirement that each feature be built only after the
    feature(s) it depends on are in place.
    """

    def __init__(self) -> None:
        self._active: List[ModuleName] = []
        self.translator = TranslationTool()

        # Activated lazily in dependency order below.
        self.users: UserManagementService
        self.tours: VirtualTourService
        self.languages: LanguageLearningService
        self.workshops: CulturalWorkshopService
        self.feedback: FeedbackService

        self._build_platform()

    # -- build orchestration -------------------------------------------------
    def _activate(self, module: ModuleName) -> None:
        for dependency in MODULE_DEPENDENCIES[module]:
            if dependency not in self._active:
                raise ModuleDependencyError(
                    f"Cannot build {module.value!r} before {dependency.value!r}."
                )
        self._active.append(module)

    def _build_platform(self) -> None:
        for module in BUILD_ORDER:
            self._activate(module)
            if module is ModuleName.USER_MANAGEMENT:
                self.users = UserManagementService()
            elif module is ModuleName.VIRTUAL_TOUR:
                self.tours = VirtualTourService(self.users)
            elif module is ModuleName.LANGUAGE_LEARNING:
                self.languages = LanguageLearningService(self.users, self.translator)
            elif module is ModuleName.CULTURAL_WORKSHOP:
                self.workshops = CulturalWorkshopService(self.users)
            elif module is ModuleName.FEEDBACK:
                self.feedback = FeedbackService(self.users)
                # Wire the feedback module to the other modules it reviews.
                self.feedback.register_target_resolver(
                    ExperienceType.VIRTUAL_TOUR, self.tours.exists
                )
                self.feedback.register_target_resolver(
                    ExperienceType.LANGUAGE_EXCHANGE, self.languages.exists
                )
                self.feedback.register_target_resolver(
                    ExperienceType.WORKSHOP, self.workshops.exists
                )

    # -- introspection -------------------------------------------------------
    @property
    def active_modules(self) -> List[str]:
        return [m.value for m in self._active]

    def build_status(self) -> Dict[str, bool]:
        return {m.value: (m in self._active) for m in BUILD_ORDER}

    def platform_summary(self) -> Dict[str, object]:
        return {
            "users": len(self.users.list_users()),
            "virtual_tours": len(self.tours.list_tours()),
            "language_sessions": len(self.languages.list_sessions()),
            "workshops": len(self.workshops.list_workshops()),
            "reviews": len(self.feedback.list_reviews()),
            "overall_average_rating": self.feedback.overall_average(),
            "active_modules": self.active_modules,
        }


