def run_self_tests() -> None:
    """Lightweight assertions that double as executable documentation."""

    def assert_raises(exc, func, *args, **kwargs):
        try:
            func(*args, **kwargs)
        except exc:
            return
        raise AssertionError(f"Expected {exc.__name__} to be raised.")

    # -- module build order -------------------------------------------------
    hub = CulturalExchangeHub()
    assert hub.active_modules == [m.value for m in BUILD_ORDER]
    assert all(hub.build_status().values())

    # -- user management ----------------------------------------------------
    user = hub.users.register("tester01", "tester@example.com", "Passw0rd1")
    assert hub.users.authenticate("tester01", "Passw0rd1").id == user.id
    assert hub.users.authenticate("tester@example.com", "Passw0rd1").id == user.id
    assert_raises(AuthenticationError, hub.users.authenticate, "tester01", "wrong-pass1")
    assert_raises(DuplicateError, hub.users.register, "tester01", "n@example.com", "Passw0rd1")
    assert_raises(ValidationError, hub.users.register, "newbie", "bad-email", "Passw0rd1")
    assert_raises(ValidationError, hub.users.register, "newbie2", "n2@example.com", "weak")
    # Stored hash must never equal the plain password.
    assert user.password_hash != "Passw0rd1" and verify_password("Passw0rd1", user.password_hash)

    # Profile must be complete before dependent features.
    assert_raises(
        ProfileIncompleteError,
        hub.tours.create_tour,
        user.id, "T", "Landmark", "desc", "https://m.example/x.glb",
    )

    # -- translation tool ---------------------------------------------------
    translator = hub.translator
    assert translator.translate("ありがとう", "Japanese", "Spanish") == "gracias"
    assert translator.translate("hola", "Spanish", "Japanese") == "こんにちは"
    assert translator.translate("Hello", "en", "fr") == "Bonjour"
    assert translator.translate("same", "en", "en") == "same"
    assert translator.translate("xyzzy", "en", "es") == "[es] xyzzy"

    # -- end-to-end demo scenario ------------------------------------------
    demo = build_demo_hub()
    summary = demo.platform_summary()
    assert summary["users"] == 3
    assert summary["virtual_tours"] == 1
    assert summary["language_sessions"] == 1
    assert summary["workshops"] == 1
    assert summary["reviews"] == 3

    tour = demo.tours.list_tours()[0]
    assert len(tour.hotspots) == 2 and "en" in tour.audio_guides
    assert demo.feedback.get_average_rating(ExperienceType.VIRTUAL_TOUR, tour.id) == 5.0
    assert demo.feedback.overall_average() == round((5 + 4 + 5) / 3, 2)

    exchange = demo.languages.list_sessions()[0]
    assert exchange.messages[0].translated_text == "gracias"
    assert exchange.messages[1].translated_text == "こんにちは"

    workshop = demo.workshops.list_workshops()[0]
    assert workshop.status is SessionStatus.ENDED
    assert workshop.questions[0].answer is not None
    assert workshop.discussions[0].replies, "discussion reply expected"

    # Capacity, duplicate and authorization guards on a fresh, OPEN workshop
    # (the demo workshop above is already ended, so it cannot be joined).
    host_id = workshop.expert_id  # an expert with a complete profile
    cap_ws = demo.workshops.create_workshop(
        host_id,
        title="Intimate Folk-Art Session",
        description="A small hands-on workshop.",
        fmt=WorkshopFormat.RECORDED,
        capacity=1,
        recording_url="https://cdn.cultural-hub.example/folk-art.mp4",
    )
    seat_user = demo.users.register("seat_user", "seat@example.com", "Passw0rd7")
    overflow_user = demo.users.register("overflow_user", "overflow@example.com", "Passw0rd8")
    demo.workshops.join_workshop(seat_user.id, cap_ws.id)
    assert_raises(CapacityError, demo.workshops.join_workshop, overflow_user.id, cap_ws.id)
    assert_raises(DuplicateError, demo.workshops.join_workshop, seat_user.id, cap_ws.id)
    assert_raises(AuthorizationError, demo.workshops.ask_question, cap_ws.id, host_id, "Hi?")

    # Feedback validation: one review per user, valid rating, existing target.
    aiko_id = next(u.id for u in demo.users.list_users() if u.username == "aiko_k")
    assert_raises(
        DuplicateError,
        demo.feedback.submit_feedback,
        aiko_id, ExperienceType.VIRTUAL_TOUR, tour.id, 3,
    )
    assert_raises(
        ValidationError,
        demo.feedback.submit_feedback,
        aiko_id, ExperienceType.WORKSHOP, workshop.id, 9,
    )
    assert_raises(
        NotFoundError,
        demo.feedback.submit_feedback,
        aiko_id, ExperienceType.VIRTUAL_TOUR, "missing", 4,
    )

    print("ALL SELF-TESTS PASSED")


def main() -> None:
    """Run the demonstration scenario and print a human-readable report."""
    # Cultural content is inherently multilingual; make stdout UTF-8 safe so the
    # demo renders cleanly on consoles with a limited default codepage.
    try:
        sys.stdout.reconfigure(encoding="utf-8", errors="replace")
    except Exception:  # pragma: no cover - depends on the host stream type
        pass

    def banner(title: str) -> None:
        print("\n" + "=" * 68)
        print(f" {title}")
        print("=" * 68)

    banner("CulturalExchangeHub — Platform Build Order")
    hub = build_demo_hub()
    for module, ready in hub.build_status().items():
        print(f"  [{'x' if ready else ' '}] {module}")

    banner("Registered Users")
    for user in hub.users.list_users():
        p = user.profile
        pic = p.picture.filename if p.picture else "—"
        print(f"  • {p.full_name} (@{user.username}) — {p.country}")
        print(f"      interests: {', '.join(p.interests)} | picture: {pic}")

    banner("Virtual Tours")
    for tour in hub.tours.list_tours():
        print(f"  • {tour.name} @ {tour.location}")
        for hotspot in tour.hotspots:
            audio = " (audio)" if hotspot.audio_url else ""
            print(f"      - hotspot: {hotspot.title}{audio}")
        print(f"      audio guides: {', '.join(tour.audio_guides) or 'none'}")

    banner("Language Exchanges")
    for session in hub.languages.list_sessions():
        print(f"  • {session.language_a} ⇄ {session.language_b} [{session.status.value}]")
        for msg in session.messages:
            print(
                f"      {msg.source_language}->{msg.target_language}: "
                f"{msg.original_text!r} → {msg.translated_text!r}"
            )

    banner("Cultural Workshops")
    for workshop in hub.workshops.list_workshops():
        print(f"  • {workshop.title} [{workshop.fmt.value}] — {workshop.status.value}")
        print(f"      attendees: {len(workshop.attendees)}/{workshop.capacity}")
        for question in workshop.questions:
            print(f"      Q: {question.text}")
            if question.answer:
                print(f"      A: {question.answer}")
        for post in workshop.discussions:
            print(f"      💬 {post.text} ({len(post.replies)} repl{'y' if len(post.replies)==1 else 'ies'})")

    banner("Feedback & Ratings")
    tour = hub.tours.list_tours()[0]
    exchange = hub.languages.list_sessions()[0]
    workshop = hub.workshops.list_workshops()[0]
    print(f"  Tour avg     : {hub.feedback.get_average_rating(ExperienceType.VIRTUAL_TOUR, tour.id)}")
    print(f"  Exchange avg : {hub.feedback.get_average_rating(ExperienceType.LANGUAGE_EXCHANGE, exchange.id)}")
    print(f"  Workshop avg : {hub.feedback.get_average_rating(ExperienceType.WORKSHOP, workshop.id)}")

    banner("Platform Summary")
    for key, value in hub.platform_summary().items():
        print(f"  {key}: {value}")

    print()
    run_self_tests()


if __name__ == "__main__":
    main()
